function makeCounter(initialValue = 0) {
  let count = initialValue;

  return {
    increment() { count++; },
    decrement() { count--; },
    getCount() { return count; }
  };
}

const counter = makeCounter(10);
counter.increment();
counter.increment();
counter.decrement();
console.log(counter.getCount()); // 11

